import logo from "./logo.svg";
import "./App.css";
import { useState } from "react";
function App() {
    return (
        <div className="App">
            <StepCounter />
            <Counter />
        </div>
    );
}

const StepCounter = function () {
    const [step, setStep] = useState(0);
    const countPlus = function () {
        setStep(step + 1);
    };
    const countMinus = function () {
        if (step <= 0) return;
        setStep(step - 1);
    };
    return (
        <div className="counter-steps">
            <button type="button" onClick={countMinus}>
                -
            </button>
            <span>Step:{step}</span>
            <button type="button" onClick={countPlus}>
                +
            </button>
        </div>
    );
};
const Counter = function () {
    return (
        <div className="counter-steps">
            <button type="button">-</button>
            <span>Count:</span>
            <button type="button">+</button>
        </div>
    );
};
export default App;
